// Package sotw provides an implementation of GRPC SoTW (State of The World) part of XDS server
package sotw

import (
        "context"
        "errors"
        "fmt"
        "strconv"
        "sync/atomic"

        core "github.com/envoyproxy/go-control-plane/envoy/config/core/v3"
        discovery "github.com/envoyproxy/go-control-plane/envoy/service/discovery/v3"
        "github.com/envoyproxy/go-control-plane/pkg/cache/v3"
        "github.com/envoyproxy/go-control-plane/pkg/log"
        "github.com/envoyproxy/go-control-plane/pkg/server/config"
        "github.com/envoyproxy/go-control-plane/pkg/server/stream/v3"
)

type Server interface {
        StreamHandler(stream stream.Stream, typeURL string) error
}

type Callbacks interface {
        // OnStreamOpen is called once an xDS stream is open with a stream ID and the type URL (or "" for ADS).
        // Returning an error will end processing and close the stream. OnStreamClosed will still be called.
        OnStreamOpen(context.Context, int64, string) error
        // OnStreamClosed is called immediately prior to closing an xDS stream with a stream ID.
        OnStreamClosed(int64, *core.Node)
        // OnStreamRequest is called once a request is received on a stream.
        // Returning an error will end processing and close the stream. OnStreamClosed will still be called.
        OnStreamRequest(int64, *discovery.DiscoveryRequest) error
        // OnStreamResponse is called immediately prior to sending a response on a stream.
        OnStreamResponse(context.Context, int64, *discovery.DiscoveryRequest, *discovery.DiscoveryResponse)
}

// NewServer creates handlers from a config watcher and callbacks.
func NewServer(ctx context.Context, cw cache.ConfigWatcher, callbacks Callbacks, opts ...config.XDSOption) Server {
        s := &server{cache: cw, callbacks: callbacks, ctx: ctx, opts: config.NewOpts()}

        // Parse through our options
        for _, opt := range opts {
                opt(&s.opts)
        }

        return s
}

// WithOrderedADS enables the internal flag to order responses
// strictly.
func WithOrderedADS() config.XDSOption {
        return func(o *config.Opts) {
                o.Ordered = true
        }
}

// WithLogger configures the server logger. Defaults to no logging
func WithLogger(logger log.Logger) config.XDSOption {
        return func(o *config.Opts) {
                o.Logger = logger
        }
}

// DeactivateLegacyWildcard deactivates legacy wildcard mode for all resource types.
// In legacy wildcard mode, empty requests to a stream, are treated as wildcard requests as long
// as there is no request made with resources or explicit wildcard requests on the same stream.
// When deactivated, empty requests are treated as a request with no subscriptions to any resource.
// This is recommended for when you are using the go-control-plane to serve grpc-xds clients.
// These clients never want to treat an empty request as a wildcard subscription.
func DeactivateLegacyWildcard() config.XDSOption {
        return config.DeactivateLegacyWildcard()
}

// DeactivateLegacyWildcardForTypes deactivates legacy wildcard mode for specific resource types.
// In legacy wildcard mode, empty requests to a stream, are treated as wildcard requests as long
// as there is no request made with resources or explicit wildcard requests on the same stream.
// When deactivated, empty requests are treated as a request with no subscriptions to any resource.
func DeactivateLegacyWildcardForTypes(types []string) config.XDSOption {
        return config.DeactivateLegacyWildcardForTypes(types)
}

type server struct {
        cache     cache.ConfigWatcher
        callbacks Callbacks
        ctx       context.Context

        // streamCount for counting bi-di streams
        streamCount int64

        // Local configuration flags for individual xDS implementations.
        opts config.Opts
}

// streamWrapper abstracts critical data passed around a stream for to be accessed
// through various code paths in the xDS lifecycle. This comes in handy when dealing
// with varying implementation types such as ordered vs unordered resource handling.
type streamWrapper struct {
        stream    stream.Stream // parent stream object
        ID        int64         // stream ID in relation to total stream count
        nonce     int64         // nonce per stream
        watches   watches       // collection of stack allocated watchers per request type
        callbacks Callbacks     // callbacks for performing actions through stream lifecycle

        node *core.Node // registered xDS client
}

// Send packages the necessary resources before sending on the gRPC stream,
// and sets the current state of the world.
func (s *streamWrapper) send(resp cache.Response) error {
        if resp == nil {
                return errors.New("missing response")
        }

        out, err := resp.GetDiscoveryResponse()
        if err != nil {
                return err
        }

        // increment nonce and convert it to base10
        out.Nonce = strconv.FormatInt(atomic.AddInt64(&s.nonce, 1), 10)

        typeURL := resp.GetRequest().GetTypeUrl()
        w, ok := s.watches.responders[typeURL]
        if !ok {
                return fmt.Errorf("no current watch for %s", typeURL)
        }

        // Track in the type subcription the nonce and objects returned to the client.
        w.sub.SetReturnedResources(resp.GetReturnedResources())
        w.nonce = out.Nonce

        // Register with the callbacks provided that we are sending the response.
        if s.callbacks != nil {
                s.callbacks.OnStreamResponse(resp.GetContext(), s.ID, resp.GetRequest(), out)
        }

        return s.stream.Send(out)
}

// Shutdown closes all open watches, and notifies API consumers the stream has closed.
func (s *streamWrapper) shutdown() {
        s.watches.close()
        if s.callbacks != nil {
                s.callbacks.OnStreamClosed(s.ID, s.node)
        }
}

// StreamHandler converts a blocking read call to channels and initiates stream processing
func (s *server) StreamHandler(stream stream.Stream, typeURL string) error {
        // a channel for receiving incoming requests
        reqCh := make(chan *discovery.DiscoveryRequest)
        go func() {
                defer close(reqCh)
                for {
                        req, err := stream.Recv()
                        if err != nil {
                                return
                        }
                        select {
                        case reqCh <- req:
                        case <-stream.Context().Done():
                                return
                        case <-s.ctx.Done():
                                return
                        }
                }
        }()

        return s.process(stream, reqCh, typeURL)
}

package sotw

import (
        "google.golang.org/grpc/codes"
        "google.golang.org/grpc/status"

        discovery "github.com/envoyproxy/go-control-plane/envoy/service/discovery/v3"
        "github.com/envoyproxy/go-control-plane/pkg/cache/types"
        "github.com/envoyproxy/go-control-plane/pkg/cache/v3"
        "github.com/envoyproxy/go-control-plane/pkg/server/stream/v3"
)

// process handles a bi-di stream request
func (s *server) processADS(sw *streamWrapper, reqCh chan *discovery.DiscoveryRequest) error {
        // Create a buffered multiplexed channel the size of the known resource types.
        respChan := make(chan cache.Response, types.UnknownType)

        // Instead of creating a separate channel for each incoming request and abandoning the old one
        // This algorithm uses (and reuses) a single channel for all request types and guarantees
        // the server will send updates over the wire in an ordered fashion.
        // Downside is there is no longer back pressure per resource.
        // There is potential for a dropped response from the cache but this is not impactful
        // to the client since SOTW version handling is global and a new sequence will be
        // initiated on a new request.
        processAllExcept := func(typeURL string) error {
                for {
                        select {
                        // We watch the multiplexed ADS channel for incoming responses.
                        case res := <-respChan:
                                if res.GetRequest().GetTypeUrl() != typeURL {
                                        if err := sw.send(res); err != nil {
                                                return err
                                        }
                                }
                        default:
                                return nil
                        }
                }
        }

        // This control loop strictly orders resources when running in ADS mode.
        // It should be treated as a child process of the original process() loop
        // and should return on close of stream or error. This will cause the
        // cleanup routines in the parent process() loop to execute.
        for {
                select {
                case <-s.ctx.Done():
                        return nil
                // We only watch the multiplexed channel since we don't use per watch channels.
                case res := <-respChan:
                        if err := sw.send(res); err != nil {
                                return status.Errorf(codes.Unavailable, err.Error())
                        }
                case req, ok := <-reqCh:
                        // Input stream ended or failed.
                        if !ok {
                                return nil
                        }

                        // Received an empty request over the request channel. Can't respond.
                        if req == nil {
                                return status.Errorf(codes.Unavailable, "empty request")
                        }

                        // Only first request is guaranteed to hold node info so if it's missing, reassign.
                        if req.GetNode() != nil {
                                sw.node = req.GetNode()
                        } else {
                                req.Node = sw.node
                        }

                        // type URL is required for ADS but is implicit for xDS
                        typeURL := req.GetTypeUrl()
                        if typeURL == "" {
                                return status.Errorf(codes.InvalidArgument, "type URL is required for ADS")
                        }

                        if s.callbacks != nil {
                                if err := s.callbacks.OnStreamRequest(sw.ID, req); err != nil {
                                        return err
                                }
                        }

                        var subscription stream.Subscription
                        w, ok := sw.watches.responders[typeURL]
                        if ok {
                                if w.nonce != "" && req.GetResponseNonce() != w.nonce {
                                        // The request does not match the stream nonce, ignore it as per
                                        // https://www.envoyproxy.io/docs/envoy/v1.28.0/api-docs/xds_protocol#resource-updates
                                        // Ignore this request and wait for the next one
                                        // This behavior is being discussed in https://github.com/envoyproxy/envoy/issues/10363
                                        // as it might create a race in edge cases, but it matches the current protocol definition
                                        s.opts.Logger.Infof("[sotw ads] Skipping request as nonce is stale for %s", typeURL)
                                        break
                                }

                                // We found an existing watch
                                // Close it to ensure the Cache will not reply to it while we modify the subscription state
                                w.close()

                                // Only process if we have an existing watch otherwise go ahead and create.
                                if err := processAllExcept(typeURL); err != nil {
                                        return err
                                }

                                subscription = w.sub
                                subscription.SetResourceSubscription(req.GetResourceNames())
                        } else {
                                s.opts.Logger.Debugf("[sotw ads] New subscription for type %s and stream %d", typeURL, sw.ID)
                                subscription = stream.NewSotwSubscription(req.GetResourceNames(), s.opts.IsLegacyWildcardActive(typeURL))
                        }

                        cancel, err := s.cache.CreateWatch(req, subscription, respChan)
                        if err != nil {
                                return err
                        }
                        sw.watches.addWatch(typeURL, &watch{
                                cancel:   cancel,
                                response: respChan,
                                sub:      subscription,
                        })
                }
        }
}

package sotw

import (
        "reflect"
        "sync/atomic"

        "google.golang.org/grpc/codes"
        "google.golang.org/grpc/status"

        core "github.com/envoyproxy/go-control-plane/envoy/config/core/v3"
        discovery "github.com/envoyproxy/go-control-plane/envoy/service/discovery/v3"
        "github.com/envoyproxy/go-control-plane/pkg/cache/v3"
        "github.com/envoyproxy/go-control-plane/pkg/resource/v3"
        "github.com/envoyproxy/go-control-plane/pkg/server/stream/v3"
)

// process handles a bi-di stream request
func (s *server) process(str stream.Stream, reqCh chan *discovery.DiscoveryRequest, defaultTypeURL string) error {
        // create our streamWrapper which can be passed down to sub control loops.
        // this is useful for abstracting critical information for various types of
        // xDS resource processing.
        sw := streamWrapper{
                stream:    str,
                ID:        atomic.AddInt64(&s.streamCount, 1), // increment stream count
                callbacks: s.callbacks,
                node:      &core.Node{}, // node may only be set on the first discovery request

                // a collection of stack allocated watches per request type.
                watches: newWatches(),
        }

        // cleanup once our stream has ended.
        defer sw.shutdown()

        if s.callbacks != nil {
                if err := s.callbacks.OnStreamOpen(str.Context(), sw.ID, defaultTypeURL); err != nil {
                        return err
                }
        }

        // type URL is required for ADS but is implicit for xDS
        if defaultTypeURL == resource.AnyType && s.opts.Ordered {
                // When using ADS we need to order responses.
                // This is guaranteed in the xDS protocol specification
                // as ADS is required to be eventually consistent.
                // More details can be found here if interested:
                // https://www.envoyproxy.io/docs/envoy/latest/api-docs/xds_protocol#eventual-consistency-considerations

                // Trigger a different code path specifically for ADS.
                // We want resource ordering so things don't get sent before they should.
                // This is a blocking call and will exit the process function
                // on successful completion.
                s.opts.Logger.Debugf("[sotw] Switching to ordered ADS implementation for stream %d", sw.ID)
                return s.processADS(&sw, reqCh)
        }

        // do an initial recompute so we can load the first 2 channels:
        // <-reqCh
        // s.ctx.Done()
        sw.watches.recompute(s.ctx, reqCh)

        for {
                // The list of select cases looks like this:
                // 0: <- ctx.Done
                // 1: <- reqCh
                // 2...: per type watches
                index, value, ok := reflect.Select(sw.watches.cases)
                switch index {
                // ctx.Done() -> if we receive a value here we return
                // as no further computation is needed
                case 0:
                        return nil
                // Case 1 handles any request inbound on the stream
                // and handles all initialization as needed
                case 1:
                        // input stream ended or failed
                        if !ok {
                                return nil
                        }

                        req := value.Interface().(*discovery.DiscoveryRequest)
                        if req == nil {
                                s.opts.Logger.Debugf("[sotw] Rejecting empty request for stream %d", sw.ID)
                                return status.Errorf(codes.Unavailable, "empty request")
                        }

                        // Only first request is guaranteed to hold node info so if it's missing, reassign.
                        if req.GetNode() != nil {
                                sw.node = req.GetNode()
                        } else {
                                req.Node = sw.node
                        }

                        // type URL is required for ADS but is implicit for xDS
                        switch {
                        case defaultTypeURL == resource.AnyType && req.GetTypeUrl() == "":
                                s.opts.Logger.Debugf("[sotw] Rejecting request as missing URL for stream %d", sw.ID)
                                return status.Errorf(codes.InvalidArgument, "type URL is required for ADS")
                        case req.GetTypeUrl() == "":
                                req.TypeUrl = defaultTypeURL
                        }

                        if s.callbacks != nil {
                                if err := s.callbacks.OnStreamRequest(sw.ID, req); err != nil {
                                        return err
                                }
                        }

                        typeURL := req.GetTypeUrl()
                        var subscription stream.Subscription
                        w, ok := sw.watches.responders[typeURL]
                        if ok {
                                if w.nonce != "" && req.GetResponseNonce() != w.nonce {
                                        // The request does not match the stream nonce, ignore it as per
                                        // https://www.envoyproxy.io/docs/envoy/v1.28.0/api-docs/xds_protocol#resource-updates
                                        // Ignore this request and wait for the next one
                                        // This behavior is being discussed in https://github.com/envoyproxy/envoy/issues/10363
                                        // as it might create a race in edge cases, but it matches the current protocol definition
                                        s.opts.Logger.Infof("[sotw] Skipping request as nonce is stale for type %s and stream %d", typeURL, sw.ID)
                                        break
                                }

                                // We found an existing watch
                                // Close it to ensure the Cache will not reply to it while we modify the subscription state
                                w.close()

                                subscription = w.sub
                                subscription.SetResourceSubscription(req.GetResourceNames())
                        } else {
                                s.opts.Logger.Debugf("[sotw] New subscription for type %s and stream %d", typeURL, sw.ID)
                                subscription = stream.NewSotwSubscription(req.GetResourceNames(), s.opts.IsLegacyWildcardActive(typeURL))
                        }

                        responder := make(chan cache.Response, 1)
                        cancel, err := s.cache.CreateWatch(req, subscription, responder)
                        if err != nil {
                                s.opts.Logger.Warnf("[sotw] Watch rejected for type %s and stream %d", typeURL, sw.ID)
                                return err
                        }
                        sw.watches.addWatch(typeURL, &watch{
                                cancel:   cancel,
                                response: responder,
                                sub:      subscription,
                        })

                        // Recompute the dynamic select cases for this stream.
                        sw.watches.recompute(s.ctx, reqCh)
                default:
                        // Channel n -> these are the dynamic list of responders that correspond to the stream request typeURL
                        // nil is used to close the streams in the caches
                        if value.IsNil() || !ok {
                                // Receiver channel was closed. TODO(jpeach): probably cancel the watch or something?
                                return status.Errorf(codes.Unavailable, "resource watch %d -> failed", index)
                        }

                        // If a non cache.Response arrived here, there are serious issues
                        res := value.Interface().(cache.Response)
                        err := sw.send(res)
                        if err != nil {
                                return err
                        }
                }
        }
}

package delta

import (
        "context"
        "errors"
        "strconv"
        "sync/atomic"

        "google.golang.org/grpc/codes"
        "google.golang.org/grpc/status"

        core "github.com/envoyproxy/go-control-plane/envoy/config/core/v3"
        discovery "github.com/envoyproxy/go-control-plane/envoy/service/discovery/v3"
        "github.com/envoyproxy/go-control-plane/pkg/cache/v3"
        "github.com/envoyproxy/go-control-plane/pkg/log"
        "github.com/envoyproxy/go-control-plane/pkg/resource/v3"
        "github.com/envoyproxy/go-control-plane/pkg/server/config"
        "github.com/envoyproxy/go-control-plane/pkg/server/stream/v3"
)

// Server is a wrapper interface which is meant to hold the proper stream handler for each xDS protocol.
type Server interface {
        DeltaStreamHandler(stream stream.DeltaStream, typeURL string) error
}

type Callbacks interface {
        // OnDeltaStreamOpen is called once an incremental xDS stream is open with a stream ID and the type URL (or "" for ADS).
        // Returning an error will end processing and close the stream. OnStreamClosed will still be called.
        OnDeltaStreamOpen(context.Context, int64, string) error
        // OnDeltaStreamClosed is called immediately prior to closing an xDS stream with a stream ID.
        OnDeltaStreamClosed(int64, *core.Node)
        // OnStreamDeltaRequest is called once a request is received on a stream.
        // Returning an error will end processing and close the stream. OnStreamClosed will still be called.
        OnStreamDeltaRequest(int64, *discovery.DeltaDiscoveryRequest) error
        // OnStreamDeltaResponse is called immediately prior to sending a response on a stream.
        OnStreamDeltaResponse(int64, *discovery.DeltaDiscoveryRequest, *discovery.DeltaDiscoveryResponse)
}

var deltaErrorResponse = &cache.RawDeltaResponse{}

type server struct {
        cache     cache.ConfigWatcher
        callbacks Callbacks

        // total stream count for counting bi-di streams
        streamCount int64
        ctx         context.Context

        // Local configuration flags for individual xDS implementations.
        opts config.Opts
}

// WithLogger configures the server logger. Defaults to no logging
func WithLogger(logger log.Logger) config.XDSOption {
        return func(o *config.Opts) {
                o.Logger = logger
        }
}

// DeactivateLegacyWildcard deactivates legacy wildcard mode for all resource types.
// In legacy wildcard mode, empty requests to a stream, are treated as wildcard requests as long
// as there is no request made with resources or explicit wildcard requests on the same stream.
// When deactivated, empty requests are treated as a request with no subscriptions to any resource.
// This is recommended for when you are using the go-control-plane to serve grpc-xds clients.
// These clients never want to treat an empty request as a wildcard subscription.
func DeactivateLegacyWildcard() config.XDSOption {
        return config.DeactivateLegacyWildcard()
}

// DeactivateLegacyWildcardForTypes deactivates legacy wildcard mode for specific resource types.
// In legacy wildcard mode, empty requests to a stream, are treated as wildcard requests as long
// as there is no request made with resources or explicit wildcard requests on the same stream.
// When deactivated, empty requests are treated as a request with no subscriptions to any resource.
func DeactivateLegacyWildcardForTypes(types []string) config.XDSOption {
        return config.DeactivateLegacyWildcardForTypes(types)
}

// NewServer creates a delta xDS specific server which utilizes a ConfigWatcher and delta Callbacks.
func NewServer(ctx context.Context, config cache.ConfigWatcher, callbacks Callbacks, opts ...config.XDSOption) Server {
        s := &server{
                cache:     config,
                callbacks: callbacks,
                ctx:       ctx,
        }

        // Parse through our options
        for _, opt := range opts {
                opt(&s.opts)
        }

        return s
}

func (s *server) processDelta(str stream.DeltaStream, reqCh <-chan *discovery.DeltaDiscoveryRequest, defaultTypeURL string) error {
        streamID := atomic.AddInt64(&s.streamCount, 1)

        // streamNonce holds a unique nonce for req-resp pairs per xDS stream.
        var streamNonce int64

        // a collection of stack allocated watches per request type
        watches := newWatches()

        node := &core.Node{}

        defer func() {
                watches.Cancel()
                if s.callbacks != nil {
                        s.callbacks.OnDeltaStreamClosed(streamID, node)
                }
        }()

        // sends a response, returns the new stream nonce
        send := func(resp cache.DeltaResponse) (string, error) {
                if resp == nil {
                        return "", errors.New("missing response")
                }

                response, err := resp.GetDeltaDiscoveryResponse()
                if err != nil {
                        return "", err
                }

                streamNonce++
                response.Nonce = strconv.FormatInt(streamNonce, 10)
                if s.callbacks != nil {
                        s.callbacks.OnStreamDeltaResponse(streamID, resp.GetDeltaRequest(), response)
                }

                return response.GetNonce(), str.Send(response)
        }

        // process a single delta response
        process := func(resp cache.DeltaResponse) error {
                typ := resp.GetDeltaRequest().GetTypeUrl()
                if resp == deltaErrorResponse {
                        return status.Errorf(codes.Unavailable, "%s watch failed", typ)
                }

                nonce, err := send(resp)
                if err != nil {
                        return err
                }

                watch := watches.deltaWatches[typ]
                watch.nonce = nonce

                watch.subscription.SetReturnedResources(resp.GetNextVersionMap())
                watches.deltaWatches[typ] = watch
                return nil
        }

        // processAll purges the deltaMuxedResponses channel
        processAll := func() error {
                for {
                        select {
                        // We watch the multiplexed channel for incoming responses.
                        case resp, more := <-watches.deltaMuxedResponses:
                                if !more {
                                        break
                                }
                                if err := process(resp); err != nil {
                                        return err
                                }
                        default:
                                return nil
                        }
                }
        }

        if s.callbacks != nil {
                if err := s.callbacks.OnDeltaStreamOpen(str.Context(), streamID, defaultTypeURL); err != nil {
                        return err
                }
        }

        for {
                select {
                case <-s.ctx.Done():
                        return nil
                // We watch the multiplexed channel for incoming responses.
                case resp, more := <-watches.deltaMuxedResponses:
                        // input stream ended or errored out
                        if !more {
                                break
                        }

                        if err := process(resp); err != nil {
                                return err
                        }
                case req, more := <-reqCh:
                        // input stream ended or errored out
                        if !more {
                                return nil
                        }

                        if req == nil {
                                return status.Errorf(codes.Unavailable, "empty request")
                        }

                        // make sure all existing responses are processed prior to new requests to avoid deadlock
                        if err := processAll(); err != nil {
                                return err
                        }

                        if s.callbacks != nil {
                                if err := s.callbacks.OnStreamDeltaRequest(streamID, req); err != nil {
                                        return err
                                }
                        }

                        // The node information might only be set on the first incoming delta discovery request, so store it here so we can
                        // reset it on subsequent requests that omit it.
                        if req.GetNode() != nil {
                                node = req.GetNode()
                        } else {
                                req.Node = node
                        }

                        // type URL is required for ADS but is implicit for any other xDS stream
                        if defaultTypeURL == resource.AnyType {
                                if req.GetTypeUrl() == "" {
                                        return status.Errorf(codes.InvalidArgument, "type URL is required for ADS")
                                }
                        } else if req.GetTypeUrl() == "" {
                                req.TypeUrl = defaultTypeURL
                        }

                        typeURL := req.GetTypeUrl()

                        // cancel existing watch to (re-)request a newer version
                        watch, ok := watches.deltaWatches[typeURL]
                        if !ok {
                                // Initialize the state of the type subscription.
                                // Since there was no previous subscription, we know we're handling the first request of this type
                                // so we set the initial resource versions if we have any.
                                // We also set the subscription as wildcard based on its legacy meaning (no resource name sent in resource_names_subscribe).
                                // If the subscription starts with this legacy mode, adding new resources will not unsubscribe from wildcard.
                                // It can still be done by explicitly unsubscribing from "*"
                                watch.subscription = stream.NewDeltaSubscription(req.GetResourceNamesSubscribe(), req.GetResourceNamesUnsubscribe(), req.GetInitialResourceVersions(), s.opts.IsLegacyWildcardActive(typeURL))
                        } else {
                                watch.Cancel()

                                // Update subscription with the new requests
                                watch.subscription.UpdateResourceSubscriptions(
                                        req.GetResourceNamesSubscribe(),
                                        req.GetResourceNamesUnsubscribe(),
                                )
                        }

                        var err error
                        watch.cancel, err = s.cache.CreateDeltaWatch(req, watch.subscription, watches.deltaMuxedResponses)
                        if err != nil {
                                return err
                        }
                        watches.deltaWatches[typeURL] = watch
                }
        }
}

func (s *server) DeltaStreamHandler(str stream.DeltaStream, typeURL string) error {
        // a channel for receiving incoming delta requests
        reqCh := make(chan *discovery.DeltaDiscoveryRequest)

        // we need to concurrently handle incoming requests since we kick off processDelta as a return
        go func() {
                defer close(reqCh)
                for {
                        req, err := str.Recv()
                        if err != nil {
                                return
                        }
                        select {
                        case reqCh <- req:
                        case <-str.Context().Done():
                                return
                        case <-s.ctx.Done():
                                return
                        }
                }
        }()
        return s.processDelta(str, reqCh, typeURL)
}

package resource

