// watches for all xDS resource types
type watches struct {
        responders map[string]*watch

        // cases is a dynamic select case for the watched channels.
        cases []reflect.SelectCase
}

// newWatches creates and initializes watches.
func newWatches() watches {
        return watches{
                responders: make(map[string]*watch, int(types.UnknownType)),
                cases:      make([]reflect.SelectCase, 0),
        }
}

// addWatch creates a new watch entry in the watches map.
// Watches are sorted by typeURL.
func (w *watches) addWatch(typeURL string, watch *watch) {
        w.responders[typeURL] = watch
}

// close all open watches
func (w *watches) close() {
        for _, watch := range w.responders {
                watch.close()
        }
}

// recomputeWatches rebuilds the known list of dynamic channels if needed
func (w *watches) recompute(ctx context.Context, req <-chan *discovery.DiscoveryRequest) {
        w.cases = w.cases[:0] // Clear the existing cases while retaining capacity.

        w.cases = append(w.cases,
                reflect.SelectCase{
                        Dir:  reflect.SelectRecv,
                        Chan: reflect.ValueOf(ctx.Done()),
                }, reflect.SelectCase{
                        Dir:  reflect.SelectRecv,
                        Chan: reflect.ValueOf(req),
                },
        )

        for _, watch := range w.responders {
                w.cases = append(w.cases, reflect.SelectCase{
                        Dir:  reflect.SelectRecv,
                        Chan: reflect.ValueOf(watch.response),
                })
        }
}

// watch contains the necessary modifiable data for receiving resource responses
type watch struct {
        cancel   func()
        response chan cache.Response

        sub stream.Subscription
        // Nonce of the latest response sent for this type
        nonce string
}

// close cancels an open watch
func (w *watch) close() {
        if w.cancel != nil {
                w.cancel()
        }
}

package delta

import (
        "github.com/envoyproxy/go-control-plane/pkg/cache/types"
        "github.com/envoyproxy/go-control-plane/pkg/cache/v3"
        "github.com/envoyproxy/go-control-plane/pkg/server/stream/v3"
)

// watches for all delta xDS resource types
type watches struct {
        deltaWatches map[string]watch

        // Opaque resources share a muxed channel
        deltaMuxedResponses chan cache.DeltaResponse
}

// newWatches creates and initializes watches.
func newWatches() watches {
        // deltaMuxedResponses needs a buffer to release go-routines populating it
        //
        // because deltaMuxedResponses can be populated by an update from the cache
        // and a request from the client, we need to create the channel with a buffer
        // size of 2x the number of types to avoid deadlocks.
        return watches{
                deltaWatches:        make(map[string]watch, int(types.UnknownType)),
                deltaMuxedResponses: make(chan cache.DeltaResponse, int(types.UnknownType)*2),
        }
}

// Cancel all watches
func (w *watches) Cancel() {
        for _, watch := range w.deltaWatches {
                watch.Cancel()
        }

        close(w.deltaMuxedResponses)
}

// watch contains the necessary modifiables for receiving resource responses
type watch struct {
        cancel func()
        nonce  string

        subscription stream.Subscription
}

// Cancel calls terminate and cancel
func (w *watch) Cancel() {
        if w.cancel != nil {
                w.cancel()
        }
}

package config

import "github.com/envoyproxy/go-control-plane/pkg/log"

// Opts for individual xDS implementations that can be
// utilized through the functional opts pattern.
type Opts struct {
        // If true respond to ADS requests with a guaranteed resource ordering
        Ordered bool

        Logger log.Logger

        // If true, deactivate legacy wildcard mode for all resource types
        legacyWildcardDeactivated bool

        // Deactivate legacy wildcard mode for specific resource types
        legacyWildcardDeactivatedTypes map[string]struct{}
}

func NewOpts() Opts {
        return Opts{
                Ordered: false,
                Logger:  log.NewDefaultLogger(),
        }
}

// IsLegacyWildcardActive returns whether legacy wildcard mode is active for the given resource type.
// Returns true if legacy wildcard mode is active, false if it has been deactivated.
func (o Opts) IsLegacyWildcardActive(typeURL string) bool {
        if o.legacyWildcardDeactivated {
                return false
        }
        if len(o.legacyWildcardDeactivatedTypes) > 0 {
                if _, found := o.legacyWildcardDeactivatedTypes[typeURL]; found {
                        return false
                }
        }
        return true
}

// Each xDS implementation should implement their own functional opts.
// It is recommended that config values be added in this package specifically,
// but the individual opts functions should be in their respective
// implementation package so the import looks like the following:
//
// `sotw.WithOrderedADS()`
// `delta.WithOrderedADS()`
//
// this allows for easy inference as to which opt applies to what implementation.
type XDSOption func(*Opts)

func DeactivateLegacyWildcard() XDSOption {
        return func(o *Opts) {
