        }
}

func DeactivateLegacyWildcardForTypes(types []string) XDSOption {
        return func(o *Opts) {
                typeMap := make(map[string]struct{}, len(types))
                for _, t := range types {
                        typeMap[t] = struct{}{}
                }
                o.legacyWildcardDeactivatedTypes = typeMap
        }
}

